import{_ as s,c as a,o as t,aN as e}from"./chunks/framework.DXgs1r1w.js";const h=JSON.parse('{"title":"HTTP 与 HTTPS 区别","description":"","frontmatter":{"date":"2024-09-07T11:00:00.000Z","title":"HTTP 与 HTTPS 区别","outline":"deep","lastUpdated":true,"footer":true,"permalink":"/pages/b3c5d9","categories":["Linux","计算机网络","HTTP"]},"headers":[],"relativePath":"Linux/计算机网络/HTTP/HTTP与HTTPS区别.md","filePath":"Linux/计算机网络/HTTP/HTTP与HTTPS区别.md","lastUpdated":1784195928000}'),r={name:"Linux/计算机网络/HTTP/HTTP与HTTPS区别.md"};function l(p,n,i,o,d,T){return t(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="http-与-https-区别" tabindex="-1">HTTP 与 HTTPS 区别 <a class="header-anchor" href="#http-与-https-区别" aria-label="Permalink to &quot;HTTP 与 HTTPS 区别&quot;">​</a></h1><h2 id="一、http-与-https-有哪些区别" tabindex="-1">一、HTTP 与 HTTPS 有哪些区别？ <a class="header-anchor" href="#一、http-与-https-有哪些区别" aria-label="Permalink to &quot;一、HTTP 与 HTTPS 有哪些区别？&quot;">​</a></h2><p><strong>HTTPS = HTTP + TLS/SSL 加密层</strong>，即&quot;在 HTTP 之下、TCP 之上&quot;插入一层安全协议，对 HTTP 的报文进行加密后再通过 TCP 传输。</p><table tabindex="0"><thead><tr><th>对比项</th><th>HTTP</th><th>HTTPS</th></tr></thead><tbody><tr><td>全称</td><td>超文本传输协议</td><td>超文本传输安全协议（HTTP over TLS）</td></tr><tr><td>端口</td><td>80</td><td>443</td></tr><tr><td>传输层之上</td><td>直接 TCP</td><td>TCP + TLS/SSL 加密层</td></tr><tr><td>安全性</td><td>明文传输，易被窃听、篡改、冒充</td><td>加密传输，防窃听/篡改/冒充</td></tr><tr><td>证书</td><td>不需要</td><td>需要 CA 颁发的数字证书</td></tr><tr><td>握手开销</td><td>无额外握手</td><td>需 TLS 握手（增加 RTT 延迟）</td></tr><tr><td>性能</td><td>略快</td><td>略慢（加解密、握手），但影响很小</td></tr><tr><td>SEO</td><td>普通</td><td>搜索引擎优先（Google/百度加权）</td></tr><tr><td>计费/监管</td><td>—</td><td>国内建站需 ICP 备案，部分场景强制 HTTPS</td></tr></tbody></table><blockquote><p>注意：<strong>HTTPS 不是独立于 HTTP 的新协议</strong>，应用层语义（方法、状态码、头部）完全一致，只是传输过程被加密了。</p></blockquote><hr><h2 id="二、https-解决了-http-的哪些问题" tabindex="-1">二、HTTPS 解决了 HTTP 的哪些问题？ <a class="header-anchor" href="#二、https-解决了-http-的哪些问题" aria-label="Permalink to &quot;二、HTTPS 解决了 HTTP 的哪些问题？&quot;">​</a></h2><p>HTTP 是明文协议，存在三大安全威胁，HTTPS 通过 TLS 一一对应解决：</p><h3 id="_1-窃听-信息泄漏-→-加密" tabindex="-1">1. 窃听（信息泄漏）→ 加密 <a class="header-anchor" href="#_1-窃听-信息泄漏-→-加密" aria-label="Permalink to &quot;1. 窃听（信息泄漏）→ 加密&quot;">​</a></h3><ul><li><strong>问题</strong>：HTTP 数据在链路上明文传输，中间人（路由器、代理、公共 Wi-Fi）可轻易抓包读取账号、密码、Cookie。</li><li><strong>解决</strong>：HTTPS 用<strong>对称加密</strong>加密业务数据，密钥通过握手安全协商，第三方无法解密。</li></ul><h3 id="_2-篡改-数据被修改-→-完整性校验" tabindex="-1">2. 篡改（数据被修改）→ 完整性校验 <a class="header-anchor" href="#_2-篡改-数据被修改-→-完整性校验" aria-label="Permalink to &quot;2. 篡改（数据被修改）→ 完整性校验&quot;">​</a></h3><ul><li><strong>问题</strong>：中间人可插入广告、篡改页面内容、修改响应（如注入恶意脚本）。</li><li><strong>解决</strong>：TLS 用 <strong>MAC（消息认证码）/ AEAD</strong> 校验每一条记录的完整性，数据被改会被立即发现并丢弃。</li></ul><h3 id="_3-冒充-身份伪造-→-身份认证" tabindex="-1">3. 冒充（身份伪造）→ 身份认证 <a class="header-anchor" href="#_3-冒充-身份伪造-→-身份认证" aria-label="Permalink to &quot;3. 冒充（身份伪造）→ 身份认证&quot;">​</a></h3><ul><li><strong>问题</strong>：攻击者可以伪造一个假网站（如仿冒银行页面）骗取用户信息（钓鱼）。</li><li><strong>解决</strong>：HTTPS 依赖 <strong>CA 数字证书</strong>验证服务器身份，浏览器确认证书可信且域名匹配后才建立连接。</li></ul><blockquote><p>一句话：<strong>HTTPS 提供了机密性（加密）、完整性（校验）、真实性（身份认证）三大保障。</strong></p></blockquote><p>补充：HTTPS 还能防<strong>重放攻击</strong>（通过序号/Nonce 机制）和<strong>降级攻击</strong>（通过 TLS 版本协商与扩展）。</p><hr><h2 id="三、https-是如何建立连接的-其间交互了什么" tabindex="-1">三、HTTPS 是如何建立连接的？其间交互了什么？ <a class="header-anchor" href="#三、https-是如何建立连接的-其间交互了什么" aria-label="Permalink to &quot;三、HTTPS 是如何建立连接的？其间交互了什么？&quot;">​</a></h2><p>HTTPS 连接建立分两个阶段：<strong>TCP 三次握手</strong>（建立可靠传输）+ <strong>TLS 握手</strong>（协商密钥、验证身份）。下面以最常见的 <strong>TLS 1.2（RSA 密钥交换）</strong> 和 <strong>TLS 1.3</strong> 思路说明。</p><h3 id="整体交互流程" tabindex="-1">整体交互流程 <a class="header-anchor" href="#整体交互流程" aria-label="Permalink to &quot;整体交互流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端                                    服务器</span></span>
<span class="line"><span>  |                                         |</span></span>
<span class="line"><span>  |  ===== TCP 三次握手 =====               |</span></span>
<span class="line"><span>  |  ---- SYN -------------------------&gt;    |</span></span>
<span class="line"><span>  |  &lt;--- SYN + ACK -------------------     |</span></span>
<span class="line"><span>  |  ---- ACK -------------------------&gt;    |</span></span>
<span class="line"><span>  |                                         |</span></span>
<span class="line"><span>  |  ===== TLS 握手 =====                   |</span></span>
<span class="line"><span>  |  ---- Client Hello -----------------&gt;   |  ① 支持的 TLS 版本、密码套件列表、客户端随机数</span></span>
<span class="line"><span>  |                                         |</span></span>
<span class="line"><span>  |  &lt;--- Server Hello -----------------    |  ② 选定的版本/套件、服务器随机数</span></span>
<span class="line"><span>  |  &lt;--- Certificate ------------------    |  ③ 服务器数字证书（含公钥）</span></span>
<span class="line"><span>  |  &lt;--- Server Key Exchange ---------     |  ④ (DH 类) 服务器公钥参数</span></span>
<span class="line"><span>  |  &lt;--- Server Hello Done ------------    |</span></span>
<span class="line"><span>  |                                         |</span></span>
<span class="line"><span>  |  ---- Client Key Exchange --------→    |  ⑤ 用证书公钥加密「预主密钥」(RSA) 或发公钥参数 (DH)</span></span>
<span class="line"><span>  |  ---- Change Cipher Spec --------→      |  ⑥ 通知：之后用协商密钥加密</span></span>
<span class="line"><span>  |  ---- Finished (加密) ------------→     |  ⑦ 校验握手完整性</span></span>
<span class="line"><span>  |                                         |</span></span>
<span class="line"><span>  |  &lt;--- Change Cipher Spec ---------      |</span></span>
<span class="line"><span>  |  &lt;--- Finished (加密) -------------     |  ⑧ 服务器同样确认</span></span>
<span class="line"><span>  |                                         |</span></span>
<span class="line"><span>  |  ===== 应用数据（对称加密传输）=====     |</span></span>
<span class="line"><span>  |  &lt;--- 加密的 HTTP 响应 -----------      |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><h3 id="关键交互步骤说明" tabindex="-1">关键交互步骤说明 <a class="header-anchor" href="#关键交互步骤说明" aria-label="Permalink to &quot;关键交互步骤说明&quot;">​</a></h3><p><strong>① Client Hello（客户端 → 服务器）</strong></p><ul><li>客户端随机数 <code>Client Random</code></li><li>支持的 TLS 版本、密码套件（Cipher Suites）列表</li><li>支持的压缩方法、扩展（如 SNI）</li></ul><p><strong>② Server Hello（服务器 → 客户端）</strong></p><ul><li>服务器随机数 <code>Server Random</code></li><li>从客户端列表中选定的 TLS 版本、密码套件</li></ul><p><strong>③ Certificate（服务器 → 客户端）</strong></p><ul><li>服务器发送 <strong>X.509 数字证书</strong>，内含服务器公钥和域名信息。</li><li>客户端据此验证：证书是否由可信 CA 签发、是否在有效期、域名是否匹配、是否吊销（OCSP/CRL）。</li></ul><p><strong>④ / ⑤ 密钥交换</strong></p><ul><li><strong>RSA 方式</strong>：客户端生成 <code>Pre-Master Secret</code>，用证书里的服务器公钥加密后发送；服务器用私钥解密。双方再用 <code>Client Random + Server Random + Pre-Master</code> 派生出相同的<strong>会话密钥（对称密钥）</strong>。</li><li><strong>DH/ECDHE 方式（更优，支持前向安全）</strong>：双方交换公开参数，各自计算出相同的预主密钥，<strong>私钥不传输</strong>。即使服务器私钥日后泄露，历史通信也无法被解密（<strong>前向保密 PFS</strong>）。</li></ul><p><strong>⑥ / ⑦ / ⑧ Change Cipher Spec 与 Finished</strong></p><ul><li>双方约定切换为对称加密。</li><li><code>Finished</code> 消息用新密钥加密，包含之前所有握手消息的 MAC，用于校验握手过程未被篡改。</li></ul><h3 id="最终产出的密钥" tabindex="-1">最终产出的密钥 <a class="header-anchor" href="#最终产出的密钥" aria-label="Permalink to &quot;最终产出的密钥&quot;">​</a></h3><p>握手完成后，双方得到相同的<strong>对称会话密钥</strong>，后续 HTTP 请求/响应都用它加解密（如 AES-GCM）。对称加密性能高，适合大量数据传输；非对称加密只用在建握手阶段，兼顾安全与效率。</p><hr><h2 id="四、tls-1-2-与-tls-1-3-的握手差异" tabindex="-1">四、TLS 1.2 与 TLS 1.3 的握手差异 <a class="header-anchor" href="#四、tls-1-2-与-tls-1-3-的握手差异" aria-label="Permalink to &quot;四、TLS 1.2 与 TLS 1.3 的握手差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>TLS 1.2</th><th>TLS 1.3</th></tr></thead><tbody><tr><td>握手往返</td><td>2-RTT（含证书）</td><td>1-RTT；重连可 0-RTT</td></tr><tr><td>密钥交换</td><td>RSA / DH 都支持（RSA 无前向安全）</td><td>仅 ECDHE（强制前向安全）</td></tr><tr><td>密码套件</td><td>多种，含弱算法</td><td>精简，移除 RSA 密钥交换、RC4、CBC 等弱算法</td></tr><tr><td>加密阶段</td><td>Change Cipher Spec 后才加密</td><td>早期数据即加密，更安全</td></tr><tr><td>性能</td><td>较慢</td><td>更快</td></tr></tbody></table><hr><h2 id="五、核心概念小结" tabindex="-1">五、核心概念小结 <a class="header-anchor" href="#五、核心概念小结" aria-label="Permalink to &quot;五、核心概念小结&quot;">​</a></h2><ul><li><strong>对称加密</strong>：加密解密用同一把密钥（如 AES），快，但密钥分发困难。</li><li><strong>非对称加密</strong>：公钥加密、私钥解密（如 RSA/ECDHE），慢，用于安全协商密钥和证书签名。</li><li><strong>数字证书 / CA</strong>：CA 用私钥给服务器公钥签名，客户端用 CA 公钥验证，形成信任链。</li><li><strong>前向保密（PFS）</strong>：每次会话用独立临时密钥，长期私钥泄露也不影响历史通信。</li></ul><blockquote><p>一句话记忆：<strong>HTTP 明文裸奔，HTTPS 靠 TLS 加密 + 证书认证；连接建立先 TCP 握手再 TLS 握手，握手用非对称加密安全协商出对称密钥，之后全程对称加密传输。</strong></p></blockquote>`,41)])])}const b=s(r,[["render",l]]);export{h as __pageData,b as default};
